mapper.insert:
insert into case_workflow_instances (
    case_id, flow_type, flow_version, status,
    current_node_key, started_by, started_at, snapshot_json
) values (
    #{caseId}, #{flowType}, #{flowVersion}, #{status},
    #{currentNodeKey}, #{startedBy}, #{startedAt}, #{snapshotJson}
)

mapper.update:
update case_workflow_instances
set status = #{status},
    current_node_key = #{currentNodeKey},
    finished_by = #{finishedBy},
    finished_at = #{finishedAt}
where id = #{id}

mapper.insert:
insert into case_workflow_tasks (
    instance_id, node_key, round_no, assignee_role,
    assignee_user_id, status, comment, acted_by, acted_at, due_at
) values (
    #{instanceId}, #{nodeKey}, #{roundNo}, #{assigneeRole},
    #{assigneeUserId}, #{status}, #{comment}, #{actedBy}, #{actedAt}, #{dueAt}
)

insert into case_workflow_action_logs (
    instance_id, task_id, action_type, actor_id, actor_name, actor_role,
    comment, payload_json, request_id, ip, user_agent, created_at
) values (
    #{instanceId}, #{taskId}, #{actionType}, #{actorId}, #{actorName}, #{actorRole},
    #{comment}, #{payloadJson}, #{requestId}, #{ip}, #{userAgent}, #{createdAt}
)
